using DiceBattleGame.Models;
using System;
using System.Drawing;
using System.IO;
using System.Media;
using System.Text.Json;
using System.Windows.Forms;

namespace DiceBattleGame
{
    public class PlayForm : Form
    {
        // Game variables
        int playerScore = 0, aiScore = 0;
        Random rnd = new Random();

        string statsFile = "stats.json";
        string betFile = "bet.json";

        // Controls
        private NumericUpDown numericBet;
        private Button btnStart;
        private Button btnRoll;
        private PictureBox picPlayer;
        private PictureBox picAI;
        private Label lblScore;
        private Label lblStatus;

        public PlayForm()
        {
            this.Text = "🎲 Dice Battle - Play";
            this.Size = new Size(500, 400);
            this.StartPosition = FormStartPosition.CenterScreen;

            InitializeControls();
        }

        private void InitializeControls()
        {
            // NumericUpDown for Bet
            numericBet = new NumericUpDown
            {
                Minimum = 1,
                Maximum = 1000,
                Value = 10,
                Size = new Size(100, 30),
                Location = new Point(50, 20)
            };
            this.Controls.Add(numericBet);

            // START BUTTON
            btnStart = new Button
            {
                Text = "START",
                Size = new Size(100, 40),
                Location = new Point(170, 20),
                Font = new Font("Segoe UI", 10, FontStyle.Bold)
            };
            btnStart.Click += BtnStart_Click;
            this.Controls.Add(btnStart);

            // ROLL BUTTON
            btnRoll = new Button
            {
                Text = "ROLL",
                Size = new Size(100, 40),
                Location = new Point(300, 20),
                Font = new Font("Segoe UI", 10, FontStyle.Bold)
            };
            btnRoll.Click += BtnRoll_Click;
            this.Controls.Add(btnRoll);

            // Player Dice PictureBox
            picPlayer = new PictureBox
            {
                Size = new Size(100, 100),
                Location = new Point(100, 80),
                SizeMode = PictureBoxSizeMode.StretchImage,
                BorderStyle = BorderStyle.FixedSingle
            };
            this.Controls.Add(picPlayer);

            // AI Dice PictureBox
            picAI = new PictureBox
            {
                Size = new Size(100, 100),
                Location = new Point(300, 80),
                SizeMode = PictureBoxSizeMode.StretchImage,
                BorderStyle = BorderStyle.FixedSingle
            };
            this.Controls.Add(picAI);

            // Score Label
            lblScore = new Label
            {
                Text = "0 : 0",
                Font = new Font("Segoe UI", 14, FontStyle.Bold),
                AutoSize = true,
                Location = new Point(220, 200)
            };
            this.Controls.Add(lblScore);

            // Status Label
            lblStatus = new Label
            {
                Text = "Place your bet and start!",
                Font = new Font("Segoe UI", 10, FontStyle.Regular),
                AutoSize = true,
                Location = new Point(150, 230)
            };
            this.Controls.Add(lblStatus);
        }

        // Start button clicked
        private void BtnStart_Click(object sender, EventArgs e)
        {
            int bet = (int)numericBet.Value;
            File.WriteAllText(betFile,
                JsonSerializer.Serialize(new BetData { BetAmount = bet }));
            lblStatus.Text = $"Bet placed: {bet}";
            playerScore = 0;
            aiScore = 0;
            lblScore.Text = "0 : 0";
            picPlayer.Image = null;
            picAI.Image = null;
        }

        // Roll button clicked
        private void BtnRoll_Click(object sender, EventArgs e)
        {
            int p = rnd.Next(1, 7);
            int a = rnd.Next(1, 7);

            picPlayer.Image = GetDiceImage(p);
            picAI.Image = GetDiceImage(a);

            if (p > a) playerScore++;
            else if (a > p) aiScore++;

            lblScore.Text = $"{playerScore} : {aiScore}";

            if (playerScore == 5 || aiScore == 5)
                EndGame();
        }

        private void EndGame()
        {
            bool win = playerScore == 5;

            GameStats stats = File.Exists(statsFile)
                ? JsonSerializer.Deserialize<GameStats>(File.ReadAllText(statsFile))
                : new GameStats();

            stats.GamesPlayed++;
            if (win) stats.GamesWon++; else stats.GamesLost++;

            File.WriteAllText(statsFile,
                JsonSerializer.Serialize(stats, new JsonSerializerOptions { WriteIndented = true }));

            MessageBox.Show(win ? "YOU WON 🎉" : "YOU LOST 💀");

            new MainForm().Show();
            this.Close();
        }

        // Convert dice number to embedded Image (Base64)
        private Image GetDiceImage(int number)
        {
            string base64 = number switch
            {
                1 => "",
                2 => "",
                3 => "",
                4 => "",
                5 => "",
                6 => "",
                _ => null
            };

            if (base64 == null) return null;

            byte[] bytes = Convert.FromBase64String(base64);
            using MemoryStream ms = new MemoryStream(bytes);
            return Image.FromStream(ms);
        }
    }
}